---
import { cn } from "@/lib/utils"
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion"
import { Button } from "@/components/ui/button"
import { Section, SectionContainer } from "@/components/ui/section"

type Props = {
  class?: string
  title: string
  description: string
  faqs: {
    id: string
    question: string
    answer: string
  }[]
  buttons?: {
    label: string
    href: string
    variant?: "default" | "outline" | "secondary" | "ghost"
  }[]
}

const { class: className, title, description, faqs, buttons } = Astro.props
---

<Section class={cn("", className)}>
  <SectionContainer class="items-center text-center">
    <div class="flex max-w-2xl flex-col items-center gap-5">
      <h2
        class="text-foreground text-3xl font-semibold tracking-tight text-balance sm:text-4xl"
      >
        {title}
      </h2>
      <p class="text-muted-foreground text-lg leading-relaxed text-balance">
        {description}
      </p>
    </div>
    {
      buttons?.length && (
        <div class="flex flex-wrap justify-center gap-3">
          {buttons.map(({ href, label, ...button }, index) => (
            <Button
              as="a"
              href={href}
              size="lg"
              variant={
                button.variant ?? (index === 0 ? "default" : "secondary")
              }
              {...button}
            >
              {label}
            </Button>
          ))}
        </div>
      )
    }
  </SectionContainer>
  <SectionContainer>
    <div class="mx-auto w-full max-w-3xl">
      <Accordion collapsible>
        {
          faqs.map((item) => (
            <AccordionItem value={item.id}>
              <AccordionTrigger>{item.question}</AccordionTrigger>
              <AccordionContent>{item.answer}</AccordionContent>
            </AccordionItem>
          ))
        }
      </Accordion>
    </div>
  </SectionContainer>
</Section>
